import { readFileSync, writeFileSync } from 'node:fs'
import { fileURLToPath } from 'node:url'
import { dirname, resolve } from 'node:path'

const __dirname = dirname(fileURLToPath(import.meta.url))
const repoRoot = resolve(__dirname, '..')
const outputPath = resolve(repoRoot, 'src/preload/index.d.ts')

const expected = `// This file is generated by scripts/generate-preload-types.mjs.
// Do not edit directly. Update src/preload/api.ts, then run npm run preload:types.

import type {
  ElectronAPI,
  MigrationFlags as PreloadMigrationFlags,
  Settings as PreloadSettings,
  StoreConfigChangePayload as PreloadStoreConfigChangePayload,
  StoreConfigChangeReason as PreloadStoreConfigChangeReason,
  WritableSettings as PreloadWritableSettings
} from './api'

export {}

declare global {
  type Settings = PreloadSettings

  type WritableSettings = PreloadWritableSettings

  type MigrationFlags = PreloadMigrationFlags

  type StoreConfigChangeReason = PreloadStoreConfigChangeReason

  type StoreConfigChangePayload = PreloadStoreConfigChangePayload

  interface Window {
    electronAPI: ElectronAPI
  }
}
`

if (process.argv.includes('--check')) {
  const actual = readFileSync(outputPath, 'utf8')

  if (actual !== expected) {
    console.error(
      'src/preload/index.d.ts is out of date. Run `npm run preload:types` and commit the result.'
    )
    process.exit(1)
  }

  process.exit(0)
}

writeFileSync(outputPath, expected)
